import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import axios from "axios";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

export default function AdminGuestActivity() {
  const { id } = useParams(); // reservation id
  const [guest, setGuest] = useState(null);
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadGuestDetails();
    loadActivities();
  }, []);

  async function loadGuestDetails() {
    try {
      const res = await axios.get(`${API_BASE}/api/reservations/${id}/`);
      setGuest(res.data);
    } catch (err) {
      console.error("Failed to load guest details", err);
    }
  }

  async function loadActivities() {
    try {
      const res = await axios.get(
        `${API_BASE}/api/admin/guest/${id}/activities/`
      );
      setActivities(res.data || []);
    } catch (err) {
      console.error("Failed to load activities", err);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div style={{ display: "flex", minHeight: "100vh", background: "#181818", color: "#f1f1f1" }}>
      <style>{`
        :root{
          --bg-sidebar:#202020;
          --card:#2a2a2a;
          --accent:#c89d5c;
          --muted:#aaa;
          --border:#333;
        }
        .sidebar{
          width:220px;
          background:var(--bg-sidebar);
          padding:20px;
          display:flex;
          flex-direction:column;
        }
        .sidebar h2{ color:var(--accent); margin-bottom:24px }
        .sidebar a{ color:var(--muted); text-decoration:none; margin:10px 0 }
        .sidebar a.active{ color:var(--accent) }
        .main{ flex:1; padding:28px }
        .card{
          background:var(--card);
          padding:16px;
          border-radius:8px;
          margin-bottom:20px;
        }
        table{
          width:100%;
          border-collapse:collapse;
        }
        th, td{
          padding:12px;
          border-bottom:1px solid var(--border);
          text-align:left;
        }
        th{ color:var(--muted) }
        tr:hover{ background:#232323 }
        .badge{
          padding:4px 10px;
          border-radius:12px;
          font-size:12px;
          font-weight:600;
        }
        .food{ background:#14532d; color:#86efac }
        .cab{ background:#1e3a8a; color:#93c5fd }
        .other{ background:#3f3f46; color:#e5e7eb }
      `}</style>

      {/* Sidebar */}
      <aside className="sidebar">
        <h2>Admin</h2>
        <a href="/admin/dashboard">Dashboard</a>
        <a href="/admin/reservations">Reservations</a>
        <a href="/admin/guest" >Guest</a>
        <a href="/admin/guest-activity" className="active">Guest Activity</a>
        <a href="/admin/rooms">Rooms</a>
        <a href="/admin/food">Food</a>
        <a href="/admin/gallery">Gallery</a>
        <a href="/admin/logout">Logout</a>
      </aside>

      {/* Main */}
      <main className="main">
        <h1 style={{ color: "var(--accent)", marginBottom: 20 }}>
          Guest Activity
        </h1>

        {/* Guest Info */}
        {guest && (
          <div className="card">
            <h3>{guest.name}</h3>
            <p>Email: {guest.email}</p>
            <p>Phone: {guest.phone}</p>
            <p>
              Stay: {guest.checkin} → {guest.checkout}
            </p>
            <p>Room Type: {guest.room_type}</p>
          </div>
        )}

        {/* Activity Table */}
        <div className="card">
          <h3 style={{ marginBottom: 12 }}>Activities</h3>

          {loading ? (
            <p>Loading activities...</p>
          ) : activities.length === 0 ? (
            <p>No activity recorded</p>
          ) : (
            <table>
              <thead>
                <tr>
                  <th>Date</th>
                  <th>Type</th>
                  <th>Description</th>
                  <th>Amount</th>
                </tr>
              </thead>
              <tbody>
                {activities.map((a, i) => (
                  <tr key={i}>
                    <td>{new Date(a.date).toLocaleString()}</td>
                    <td>
                      <span className={`badge ${a.type}`}>
                        {a.type.toUpperCase()}
                      </span>
                    </td>
                    <td>{a.description}</td>
                    <td>₹{Number(a.amount).toFixed(2)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </main>
    </div>
  );
}
